mapper.select:
SELECT id, goods_id, total_stock, locked_stock, sold_count, version, updated_at
FROM t_stock
WHERE goods_id = #{goodsId}

mapper.update:
UPDATE t_stock
SET locked_stock = locked_stock + #{quantity},
    version      = version + 1,
    updated_at   = NOW()
WHERE goods_id = #{goodsId}
  AND (total_stock - locked_stock - sold_count) >= #{quantity}
  AND version = #{version}

UPDATE t_stock
SET locked_stock = locked_stock - #{quantity},
    version      = version + 1,
    updated_at   = NOW()
WHERE goods_id = #{goodsId}
  AND locked_stock >= #{quantity}
  AND version = #{version}
